def verify_and_run():
    print("\n" + "☠️"*20)
    print("   JARVIS SECURE REPOSITORY OVERLAY")
    print("☠️"*20)
    
    # இங்க உங்களுக்கு என்ன Secret Passcode வேணுமோ அதை மாத்திக்கோங்க மச்சான்!
    # உதாரணத்துக்கு "srilanka2026" அல்லது "myjarvis" எது வேணா வைக்கலாம்.
    passcode = input("\nEnter Secret Passcode to decrypt and run: ")
    
    if passcode == "dexsan123":
        print("\n[+] Passcode Verified! Decrypting core payload...")
        try:
            cipher_suite = Fernet(SECRET_KEY)
            decrypted_code = cipher_suite.decrypt(ENCRYPTED_DATA).decode('utf-8')
            
            # டிகிரிப்ட் செய்த கோடை மெமரியிலேயே ரன் பண்ணும் மேஜிக் 
            exec(decrypted_code, globals())
        except Exception as e:
            print(f"\n[-] Encryption Error: Core mismatch. {e}")
    else:
        print("\n[-] Access Denied: Incorrect Passcode. Exiting tools...")
        sys.exit()

